## Complete Code Report: Hit Animation, Damage Text, and Blocked Tile Animations

### 1. Damage Text Element Creation and Positioning

**File: `/Users/garreltmock/Projects/match-2048/src/merge-processor.js` (Lines 671-690)**

```javascript
// Visual feedback: shake + floating damage text
const el = isRectangularBlocked(tile)
    ? document.querySelector(`[data-rect-id="${tile.rectId}"]`)
    : document.querySelector(`[data-row="${entry.row}"][data-col="${entry.col}"]`);
if (el) {
    const ratio = entry.damage / oldLife;
    const intensity = Math.min(1 + ratio * 9, 10);
    el.style.setProperty("--shake-intensity", `${intensity}px`);
    el.classList.add("blocked-damaged");
    el.dataset.life = tile.lifeValue;

    const dmgText = document.createElement("span");
    dmgText.className = "damage-text";
    dmgText.textContent = `-${entry.damage}`;
    el.appendChild(dmgText);

    setTimeout(() => {
        el.classList.remove("blocked-damaged");
        dmgText.remove();
    }, 800);
}
```

### 2. Damage Text CSS Styling and Animation

**File: `/Users/garreltmock/Projects/match-2048/styles/game.css` (Lines 985-1015)**

```css
/* Floating damage text */
@keyframes damageFloat {
    0% {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
    20% {
        opacity: 1;
        transform: translateY(-20%) scale(1.1);
    }
    100% {
        opacity: 0;
        transform: translateY(-80%) scale(0.8);
    }
}

.damage-text {
    position: absolute;
    bottom: 60%;
    left: 60%;
    z-index: 300;
    pointer-events: none;
    font-weight: bolder;
    font-style: italic;
    font-size: clamp(1.5rem, 45cqw, 2rem);
    color: #ff4444;
    text-shadow:
        0 0 3px rgba(0, 0, 0, 0.8),
        0 1px 2px rgba(0, 0, 0, 0.6);
    animation: damageFloat 0.8s ease-out forwards;
}
```

**Key features:**
- Uses `clamp(1.5rem, 45cqw, 2rem)` for responsive font sizing (45% of container query width)
- `z-index: 300` places text above tiles
- Text starts at bottom-60%, left-60% (relative to blocked tile)
- Animates upward with fade-out over 0.8s

### 3. Blocked Tile Shake Animation (Hit Feedback)

**File: `/Users/garreltmock/Projects/match-2048/styles/game.css` (Lines 958-983)**

```css
/* Blocked tile damage shake */
@keyframes blockedShake {
    0%,
    100% {
        transform: translateX(0);
    }
    15% {
        transform: translateX(calc(-1 * var(--shake-intensity)));
    }
    30% {
        transform: translateX(var(--shake-intensity));
    }
    45% {
        transform: translateX(calc(-0.7 * var(--shake-intensity)));
    }
    60% {
        transform: translateX(calc(0.5 * var(--shake-intensity)));
    }
    75% {
        transform: translateX(calc(-0.3 * var(--shake-intensity)));
    }
}

.gem.blocked-damaged {
    animation: blockedShake 0.35s ease-out;
}
```

**How intensity is calculated (from merge-processor.js):**
```javascript
const ratio = entry.damage / oldLife;
const intensity = Math.min(1 + ratio * 9, 10);
el.style.setProperty("--shake-intensity", `${intensity}px`);
```

- Shake intensity scales from 1-10px based on damage ratio
- Damaging 50% of life = 5.5px shake, max 10px for full damage

### 4. Blocked Tile Removal Animation

**File: `/Users/garreltmock/Projects/match-2048/src/animator.js` (Lines 192-216, 218-277)**

```javascript
function animateRectangularBlockRemoval(game, tile, speedMultiplier = 1) {
    // Capture the rectId and dimensions (in case tile object reference changes)
    const rectId = tile.rectId;
    const anchorRow = tile.rectAnchor.row;
    const anchorCol = tile.rectAnchor.col;
    const rectHeight = tile.rectHeight;
    const rectWidth = tile.rectWidth;

    // Remove from board state FIRST (before animation) - all board reads
    // during animation use DOM state, not game.board, so this is safe.
    for (let r = anchorRow; r < anchorRow + rectHeight; r++) {
        for (let c = anchorCol; c < anchorCol + rectWidth; c++) {
            const boardTile = game.board[r]?.[c];
            if (boardTile && boardTile.rectId === rectId) {
                game.board[r][c] = null;
            }
        }
    }

    // Then trigger visual animation
    const blockedElement = document.querySelector(`[data-rect-id="${rectId}"]`);
    if (blockedElement) {
        blockedElement.classList.add("disappear");
    }
}

export function animateUnblocking(game, blockedTiles, updateBlockedTileGoalsCallback, updateGoalDisplayCallback, speedMultiplier = 1) {
    if (blockedTiles.length === 0) return;

    // Process each blocked tile for animation
    blockedTiles.forEach((blockedEntry) => {
        const tile = blockedEntry.tile || game.board[blockedEntry.row][blockedEntry.col];

        if (!tile) return; // Already removed

        // NEW: Handle individual cell X removal for merge-count tiles
        if (blockedEntry.isMergeCount && !blockedEntry.isFullRemoval) {
            // Remove just the X visual for this specific cell
            const blockedElement = document.querySelector(`[data-rect-id="${tile.rectId}"]`);
            if (blockedElement) {
                const xMarker = blockedElement.querySelector(`[data-cell-key="${blockedEntry.cellKey}"]`);
                if (xMarker) {
                    xMarker.classList.add("cell-x-removing");
                    setTimeout(() => xMarker.remove(), 300 * speedMultiplier);
                }
            }
            // Don't remove tile from board - just cleared one cell
            return;
        }

        // NEW: Full rectangular block removal (all cells cleared)
        if (blockedEntry.isFullRemoval && isRectangularBlocked(tile)) {
            animateRectangularBlockRemoval(game, tile, speedMultiplier);
            return;
        }

        // EXISTING: Single-cell blocked tile animation
        // Remove from board state FIRST (before animation)
        game.board[blockedEntry.row][blockedEntry.col] = null;

        const blockedElement = document.querySelector(
            `[data-row="${blockedEntry.row}"][data-col="${blockedEntry.col}"]`
        );

        if (blockedElement) {
            // Add disappear animation class (reverse bounce - inflate then shrink)
            blockedElement.classList.add("disappear");
        }
    });
}
```

### 5. Blocked Tile Disappear Animation

**File: `/Users/garreltmock/Projects/match-2048/style.css` (Lines 163-192)**

```css
@keyframes popShrink {
    0% {
        transform: scale(1);
    }
    20% {
        transform: scale(1.1); /* kurz größer */
    }
    100% {
        transform: scale(0);
    }
}

.disappear {
    animation: popShrink 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
}

/* Also references the old unblock-move animation: */
@keyframes unblock-move {
    0% {
        transform: scale(1);
        opacity: 1;
    }
    50% {
        transform: scale(0.8);
        opacity: 0.7;
    }
    100% {
        transform: scale(0.3);
        opacity: 0;
    }
}
```

**Blocked tile classes using these animations:**

**File: `/Users/garreltmock/Projects/match-2048/styles/game.css` (Lines 905-908, 1017-1020)**

```css
.gem.tile-BLOCKED.unblocking {
    animation: unblock-move 0.6s ease-out forwards;
    z-index: 200;
}

.gem.tile-BLOCKED_WITH_LIFE.unblocking {
    animation: unblock-move 0.6s ease-out forwards;
    z-index: 200;
}
```

### 6. Z-Index Hierarchy

**File: `/Users/garreltmock/Projects/match-2048/styles/game.css` and `/Users/garreltmock/Projects/match-2048/style.css`**

```css
/* Damage text layer */
.damage-text {
    z-index: 300;  /* Highest - floats above tiles */
}

/* Blocked tile removal animation */
.gem.tile-BLOCKED.unblocking,
.gem.tile-BLOCKED_WITH_LIFE.unblocking {
    z-index: 200;  /* Above normal tiles during removal */
}

/* Normal tile during animation/drag */
.gem.dragging {
    z-index: 10;
}

/* UI controls */
.power-ups {
    z-index: 10;
}

.back-btn,
.game-info-btn {
    z-index: 10;
}
```

### 7. Cell X Marker Removal (Merge-Count Tiles)

**File: `/Users/garreltmock/Projects/match-2048/styles/game.css` (Lines 1122-1139)**

```css
/* X removal animation */
@keyframes cell-x-fadeout {
    0% {
        opacity: 1;
        transform: scale(1);
    }
    50% {
        opacity: 0.5;
        transform: scale(1.2);
    }
    100% {
        opacity: 0;
        transform: scale(0);
    }
}

.cell-x-removing {
    animation: cell-x-fadeout 0.3s ease-out forwards;
}
```

### Summary

- **Damage text positioning**: Absolute, bottom-60% left-60% with `clamp()` font sizing
- **Damage text animation**: `damageFloat` keyframes over 0.8s with upward translation and fade
- **Hit shake feedback**: `blockedShake` animation with CSS variable intensity (1-10px)
- **Blocked tile removal**: `popShrink` animation with ease-in cubic-bezier, scales from 1 to 0
- **Z-index stack**: Damage text (300) > Blocked removal (200) > Normal tiles (10)
- **Speed multiplier**: Animator respects speedMultiplier for tutorial slowdown

