.gem.tile-JOKER {
    background: var(--tile-joker-bg);
    color: var(--tile-joker-color);
    border: 3px solid var(--tile-joker-border);
    cursor: pointer;
    position: relative;
    flex-direction: column;
    justify-content: center;

    .star-value {
        font-size: 85cqw;
        line-height: 1em;
        transform: translateY(8cqw);
        font-weight: bold;
    }

    .preview-value {
        opacity: 0.6;
        position: absolute;
        bottom: 2cqw;
    }
}

.gem.cursed-tile {
    background: var(--tile-cursed-bg) !important;
    border: 3px solid var(--tile-cursed-border) !important;
    position: relative;
    color: var(--tile-cursed-color);
}

.gem.cursed-tile::after {
    content: attr(data-cursed-moves);
    position: absolute;
    bottom: -3px;
    right: -3px;
    font-family: Nunito;
    font-size: clamp(12px, 2.5vw, 16px);
    font-weight: 900;
    background: var(--tile-cursed-badge-bg);
    width: 33%;
    height: 33%;
    border-radius: 35%;
    color: var(--tile-cursed-color);
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px solid var(--tile-cursed-badge-bg);
    box-shadow: 0 0 8px rgba(156, 39, 176, 0.6);
}

.goal-tile {
    margin-top: -10%;
    transform-origin: center center;
    transform: scale(0.8);
}

.gem.cursed-disappear {
    animation: cursedFadeOut 0.4s ease-out forwards;
}

@keyframes cursedFadeOut {
    0% {
        opacity: 1;
        transform: scale(1);
    }
    100% {
        opacity: 0;
        transform: scale(0.5);
    }
}

.gem.cursed-implode {
    animation: cursedImplode 0.4s ease-out forwards;
}

@keyframes cursedImplode {
    0% {
        transform: scale(1);
        opacity: 1;
    }
    50% {
        transform: scale(1.3);
        box-shadow: 0 0 30px rgba(156, 39, 176, 1);
    }
    100% {
        transform: scale(0);
        opacity: 0;
    }
}

.gem.cursed-sucked {
    background: var(--tile-cursed-bg) !important;
    transition: background 0.1s ease-out;
}

.gem.freeswap-tile {
    border: 3px solid var(--tile-freeswap-border);
    position: relative;
}

.gem.sticky-freeswap-tile {
    border: 3px solid var(--tile-freeswap-border);
    position: relative;
}

.gem.sticky-freeswap-tile::after,
.gem.freeswap-tile::after {
    content: "";
    position: absolute;
    top: -3px;
    right: -3px;
    width: 40%;
    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-freeswap-badge-bg);
    background-image: url("../assets/arrow-all-directions.svg");
    background-size: 75%;
    background-position: center;
    background-repeat: no-repeat;
    display: flex;
    align-items: center;
    justify-content: center;
}

.gem.freeswap-horizontal-tile {
    border: 3px solid var(--tile-freeswap-border);
    position: relative;
}

.gem.freeswap-horizontal-tile::after {
    content: "";
    position: absolute;
    top: -3px;
    right: -3px;
    width: 40%;
    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-freeswap-badge-bg);
    background-image: url("../assets/arrow-horizontal.svg");
    background-size: 75%;
    background-position: center;
    background-repeat: no-repeat;
    display: flex;
    align-items: center;
