}

.gem.freeswap-vertical-tile::after {
    content: "";
    position: absolute;
    top: -3px;
    right: -3px;
    width: 40%;
    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-freeswap-badge-bg);
    background-image: url("../assets/arrow-vertical.svg");
    background-size: 38%;
    background-position: center;
    background-repeat: no-repeat;
    display: flex;
    align-items: center;
    justify-content: center;
}

.gem.hammer-tile {
    border: 3px solid var(--tile-hammer-border);
    position: relative;
}

.gem.hammer-tile::after {
    content: "🔨";
    position: absolute;
    top: -3px;
    right: -3px;
    font-size: clamp(8px, 2vw, 16px);
