    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-hammer-badge-bg);
    color: var(--tile-hammer-badge-color);
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
}

.gem.halver-tile {
    border: 3px solid var(--tile-halver-border);
    position: relative;
}

.gem.halver-tile::after {
    content: "✂️";
    position: absolute;
    top: -3px;
    right: -3px;
    font-size: clamp(8px, 2vw, 16px);
    width: 40%;
    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-halver-badge-bg);
    color: var(--tile-halver-badge-color);
    font-weight: bold;
