/* Remove teleport styling after tile has been used */
.gem.teleport-tile.teleport-used {
    border: none;
}

.gem.teleport-tile.teleport-used::after {
    display: none;
}

/* Wild Teleport tile - Joker with teleport ability */
.gem.wild-teleport-tile {
    border: 3px solid var(--tile-wild-teleport-border);
    position: relative;
}

.gem.wild-teleport-tile::after {
    content: "🚀";
    position: absolute;
    top: -3px;
    right: -3px;
    font-size: clamp(8px, 2vw, 16px);
    width: 40%;
    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-wild-teleport-badge-bg);
    color: white;
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
}

.gem.plus-tile {
    border: 3px solid var(--tile-plus-border);
    position: relative;
}

.gem.plus-tile::after {
    content: "+";
    position: absolute;
    top: -3px;
    right: -3px;
    width: 35%;
    height: 35%;
    border-radius: 35%;
    background: var(--tile-plus-badge-bg);
    color: var(--tile-plus-badge-color);
    font-size: clamp(8px, 3vw, 16px);
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
}

.gem.selected {
    box-shadow: 0 0 15px 5px var(--tile-teleport-border);
    animation: pulse-selected 1s infinite;
}

@keyframes pulse-selected {
    0%,
    100% {
        box-shadow: 0 0 10px 3px var(--tile-teleport-border);
    }
    50% {
        box-shadow: 0 0 20px 8px var(--tile-teleport-border);
    }
}

.gem.tile-BLOCKED {
    background: var(--tile-blocked-bg);
    color: transparent;
    border: 2px solid var(--tile-blocked-border);
    position: relative;
    overflow: hidden;
}

.gem.tile-BLOCKED::before {
    content: "";
    position: absolute;
    top: 45%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
}

.gem.tile-BLOCKED.unblocking {
    animation: unblock-move 0.6s ease-out forwards;
    z-index: 200;
}

.gem.tile-BLOCKED_WITH_LIFE {
    background: var(--tile-blocked-bg);
    color: var(--tile-blocked-life-color);
    border: 2px solid var(--tile-blocked-border);
    font-size: clamp(1.2rem, 4vw, 1.8rem);
    font-weight: bold;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: visible;
}

.gem.tile-BLOCKED_WITH_LIFE::before {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
    z-index: 0;
}

.gem.tile-BLOCKED_WITH_LIFE::after {
    content: attr(data-life);
    position: relative;
    z-index: 1;
    color: var(--tile-blocked-life-color);
    font-size: clamp(1rem, 40cqw, 1.2rem);
    font-weight: bold;
}

/* Blocked tile damage shake */
@keyframes blockedShake {
    0%,
    100% {
        transform: translateX(0);
    }
    15% {
        transform: translateX(calc(-1 * var(--shake-intensity)));
    }
    30% {
        transform: translateX(var(--shake-intensity));
    }
    45% {
        transform: translateX(calc(-0.7 * var(--shake-intensity)));
    }
    60% {
        transform: translateX(calc(0.5 * var(--shake-intensity)));
    }
    75% {
        transform: translateX(calc(-0.3 * var(--shake-intensity)));
    }
}

.gem.blocked-damaged {
    animation: blockedShake 0.35s ease-out;
}

/* Floating damage text */
@keyframes damageFloat {
    0% {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
    20% {
        opacity: 1;
        transform: translateY(-20%) scale(1.1);
    }
    100% {
        opacity: 0;
        transform: translateY(-80%) scale(0.8);
    }
}

.damage-text {
    position: absolute;
    bottom: 60%;
    left: 60%;
    z-index: 300;
    pointer-events: none;
    font-weight: bolder;
    font-style: italic;
    font-size: clamp(1.5rem, 45cqw, 2rem);
    color: #ff4444;
    text-shadow:
        0 0 3px rgba(0, 0, 0, 0.8),
        0 1px 2px rgba(0, 0, 0, 0.6);
    animation: damageFloat 0.8s ease-out forwards;
}

.gem.tile-BLOCKED_WITH_LIFE.unblocking {
    animation: unblock-move 0.6s ease-out forwards;
    z-index: 200;
}

.gem.tile-BLOCKED_MOVABLE {
    background: var(--tile-blocked-movable-bg);
    color: transparent;
    border: 2px solid var(--tile-blocked-movable-border);
    position: relative;
    overflow: visible;
    cursor: pointer;
}

.gem.tile-BLOCKED_MOVABLE::before {
    content: "";
    position: absolute;
    top: 45%;
    left: 50%;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
    transform: translate(-50%, -50%);
}

.gem.tile-BLOCKED_MOVABLE::after {
    content: "";
    width: 60%;
    height: 60%;
    position: absolute;
    top: 44%;
    left: 50%;
    transform: translate(-50%, -50%);
    background-image: url("../assets/arrow-all-directions.svg");
    background-size: 60%;
    background-position: center;
    background-repeat: no-repeat;
    z-index: 1;
    opacity: 0.7;
}

/* Blocked tiles with merge count (per-cell tracking) */
.gem.tile-BLOCKED.tile-BLOCKED-merge-count {
    background: var(--tile-blocked-bg);
    border: 2px solid var(--tile-blocked-border);

    /* CSS Grid for positioning X markers */
    display: grid;
    grid-template-columns: repeat(var(--rect-width), 1fr);
    grid-template-rows: repeat(var(--rect-height), 1fr);
    gap: clamp(1px, 0.7vw, 3px); /* Match board gap */

    &::before {
        display: none;
    }
}

/* Individual X marker cells */
.cell-x-marker {
    position: relative;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;
}

/* X pattern for each cell */
.cell-x-marker::before {
    content: "";
    position: absolute;
    width: 60%;
    height: 60%;
    background:
        linear-gradient(
            45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        ),
        linear-gradient(
            -45deg,
            transparent 30%,
            var(--tile-blocked-x-color) 30%,
            var(--tile-blocked-x-color) 70%,
            transparent 70%
        );
}

/* X removal animation */
@keyframes cell-x-fadeout {
    0% {
        opacity: 1;
        transform: scale(1);
    }
    50% {
        opacity: 0.5;
        transform: scale(1.2);
    }
    100% {
        opacity: 0;
        transform: scale(0);
    }
}

.cell-x-removing {
    animation: cell-x-fadeout 0.3s ease-out forwards;
}

/* Rectangular blocked tiles */
.gem.rectangular-blocked {
    /* Override aspect-ratio for rectangular shapes */
    aspect-ratio: auto;

    /* Ensure proper sizing within spanned grid cells */
    width: 100%;
    height: 100%;
    border-radius: 20px;

    &.goal-tile {
        width: 30vw;
        height: 30vw;
    }
}

.gem.matched {
    animation: match-animation 0.5s ease-out forwards;
}

.gem.sliding {
    z-index: 20;
    transition:
        transform 0.4s ease-out,
        opacity 0.3s ease-out;
}

.gem.merge-target {
    animation: merge-pulse 0.4s ease-in forwards;
}

/* .gem.falling animation is now handled via inline styles in animator.js */

.gem.new-gem {
    opacity: 0; /* Start invisible until animation begins */
    animation: new-gem-animation 0.4s ease-in forwards;
}

.bottom-container {
    flex: 1 1 0;
    min-height: clamp(100px, 20vw, 150px);
    position: relative;
}

.controls {
    display: flex;
    gap: clamp(6px, 2vw, 10px);
    justify-content: center;
    flex-shrink: 0;
    align-items: center;
    position: absolute;
    bottom: 6vh;
    left: 0;
    width: 100%;
}

.control-btn {
    background: rgba(255, 255, 255, 0.1);
    color: white;
    padding: clamp(8px, 2vw, 12px) clamp(22px, 8vw, 30px);
    border-radius: 16px;
    font-size: 24px;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.3s ease;
    backdrop-filter: blur(10px);
    font-family: Nunito;
    font-weight: 900;
    border: none;
}

.next {
    background: #aee96b;
    box-shadow: 0 -4px 0 0 rgba(0, 0, 0, 0.25) inset;
    color: black;
    border: 2px solid black;
    /* position: absolute; */
}

.continue {
    background: #141414;
    box-shadow: 0 -4px 0 0 rgba(0, 0, 0, 0.25) inset;
    color: white;
    position: absolute;
}

/* Power-ups */
.power-ups {
    display: flex;
    gap: clamp(8px, 2vw, 16px);
    justify-content: center;
    position: relative;
    z-index: 10;
}

.power-up-cycle-indicator {
    margin-top: 8px;
    display: none;
    justify-content: center;
    gap: clamp(8px, 2vw, 16px);
}

.cycle-dot {
    width: clamp(60px, 20vw, 120px);
    display: flex;
    justify-content: center;
}

.cycle-dot.active::after {
    content: "";
    width: 8px;
    height: 8px;
    background: var(--tile-freeswap-badge-bg);
    border-radius: 50%;
}

.power-up-btn {
    width: clamp(60px, 20vw, 120px);
    height: clamp(60px, 20vw, 120px);
    border-radius: 24px;
    border: 4px solid #000;
    background: #141414;
    color: white;
    font-size: clamp(16px, 8vw, 50px);
    cursor: pointer;
    backdrop-filter: blur(10px);
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
}

.power-up-btn.disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Locked power-up styling */
.power-up-btn.locked {
    opacity: 0;
    filter: grayscale(100%);
    cursor: not-allowed;
    position: relative;
    display: none;
}

.power-up-btn.active {
    background: #aee96b;
    box-shadow: 0 -6px 0 0 rgba(0, 0, 0, 0.25) inset;
}

/* Power-up use indicator */
.use-indicator {
    position: absolute;
    top: -10%;
    right: -10%;
    width: clamp(26px, 8vw, 50px);
    height: clamp(26px, 8vw, 50px);
    background: #ff401a;
    box-shadow: 0 -0.5vw 0 0 rgba(0, 0, 0, 0.25) inset;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    /* border: 2px solid #902009; */
    z-index: 10;

    color: #fff;
    /* text-shadow: -2px -2px 0 black, 2px -2px 0 black, -2px 2px 0 black, 2px 2px 0 black; */
    font-family: Nunito;
    font-size: 16px;
    font-weight: 900;

    &.transient-count {
        background: var(--tile-freeswap-badge-bg);
    }
}

.use-indicator stroked-text {
    width: 100%;
    height: 100%;
    margin-top: -10%;
}

/* Power-up visual feedback */
.gem.selected {
    border: 3px solid #4caf50;
    box-shadow: 0 0 20px rgba(76, 175, 80, 0.8);
    animation: pulse 1s infinite;
}

@keyframes pulse {
    0% {
        transform: scale(1);
    }
    50% {
        transform: scale(1.05);
    }
    100% {
        transform: scale(1);
    }
}

@keyframes match-animation {
    0% {
        transform: scale(1);
        opacity: 1;
    }
    50% {
        transform: scale(1.3);
        opacity: 0.8;
    }
    100% {
        transform: scale(0);
        opacity: 0;
    }
}

@keyframes fall-animation {
    0% {
        transform: translateY(0);
        opacity: 1;
    }
    100% {
        transform: translateY(0);
        opacity: 1;
    }
}

