        transform: scale(0.5);
    }
}

.gem.cursed-implode {
    animation: cursedImplode 0.4s ease-out forwards;
}

@keyframes cursedImplode {
    0% {
        transform: scale(1);
        opacity: 1;
    }
    50% {
        transform: scale(1.3);
