/* Power-ups */
.power-ups {
    display: flex;
    gap: clamp(8px, 2vw, 16px);
    justify-content: center;
    position: relative;
    z-index: 10;
}

.power-up-cycle-indicator {
    margin-top: 8px;
    display: none;
    justify-content: center;
    gap: clamp(8px, 2vw, 16px);
}

.cycle-dot {
    width: clamp(60px, 20vw, 120px);
    display: flex;
    justify-content: center;
}

.cycle-dot.active::after {
    content: "";
    width: 8px;
    height: 8px;
    background: var(--tile-freeswap-badge-bg);
    border-radius: 50%;
}

.power-up-btn {
    width: clamp(60px, 20vw, 120px);
    height: clamp(60px, 20vw, 120px);
    border-radius: 24px;
    border: 4px solid #000;
    background: #141414;
    color: white;
    font-size: clamp(16px, 8vw, 50px);
    cursor: pointer;
    backdrop-filter: blur(10px);
