/* Formation Power-Up Reward Animation */
.formation-powerup-animation {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 1000;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    animation: formationPowerUpFloat 2s ease-out forwards;
    pointer-events: none;
}

.formation-powerup-headline {
    animation: formationPowerUpPop 0.3s ease-out;
    /* filter: drop-shadow(0 0 20px rgba(255, 215, 0, 0.8)); */
}

.formation-powerup-subtitle {
    display: flex;
    align-items: center;
    gap: 4px;
    animation: formationPowerUpPop 0.3s ease-out 0.1s backwards;
    /* filter: drop-shadow(0 0 15px rgba(100, 200, 255, 0.8)); */
}

@keyframes formationPowerUpFloat {
    0% {
        opacity: 1;
        transform: translate(-50%, -50%) scale(1);
    }
    70% {
        opacity: 1;
        transform: translate(-50%, -60%) scale(1.05);
    }
    100% {
        opacity: 0;
        transform: translate(-50%, -80%) scale(0.9);
    }
}

@keyframes formationPowerUpPop {
    0% {
        transform: scale(0.5);
        opacity: 0;
    }
    70% {
        transform: scale(1.1);
    }
    100% {
        transform: scale(1);
        opacity: 1;
    }
}

